class Solution {
public:
    int numberOfStableArrays(int zero, int one, int limit) {
        const int MOD = 1e9 + 7;
        long long dp[limit + 1][one + 1] = {};
        for (int i = 1; i <= limit; i++) {
            for (int j = 1; j <= one; j++) {
                for (int k = 1; k <= i && k <= j; k++) {
                    dp[i][j] = (dp[i][j] + dp[i - k][j - k]) % MOD;
                }
            }
        }
        long long res = 0;
        for (int i = 1; i <= limit; i++) {
            for (int j = 1; j <= one; j++) {
                res = (res + dp[i][j]) % MOD;
            }
        }
        return res;
    }
};
